--游戏阶段提示

GameTip = {}
GameTip.Tips = {}

function GameTip:init(configs)
    for _, config in pairs(configs) do
        local item = {}
        item.id = tonumber(config.id)
        item.gameTip = config.gameTip
        item.time = tonumber(config.time)
        self.Tips[item.id] = item
    end
end

function GameTip:getTipById(id)
    local item = self.Tips[tonumber(id)]
    if item ~= nil then
        return item
    end
end

return GameTip